if (typeof timeout === 'number' && timeout < 0) {
  throw new TypeError(`Timeout must be non-negative, got ${timeout}`);
}

import test from 'ava';
import got from '../source/index.js';

test('default retry count is 2', t => {
  const options = new got.Options({ retry: { limit: 2 } });
  t.is(options.retry.limit, 2);
});

test('custom retry limit', t => {
  const options = new got.Options({ retry: { limit: 5 } });
  t.is(options.retry.limit, 5);
});

test('retry limit 0 disables retries', t => {
  const options = new got.Options({ retry: { limit: 0 } });
  t.is(options.retry.limit, 0);
});
